function DefaultCurrency635() {}
DefaultCurrency635.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency635.tabIndex = -1;
DefaultCurrency635.maxLength = 1;
DefaultCurrency635.isReadOnly = function(){return true;}
DefaultCurrency635.isTemporary = function(){return true;}
DefaultCurrency635.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency635.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }

